// Generated by Claude Opus 4.6

import { BackupValidationResult } from '@eclipse-che/common';
import { ValidatedOptions } from '@patternfly/react-core';
import userEvent from '@testing-library/user-event';
import React from 'react';

import { ImageUrlField } from '@/pages/RestoreFromBackup/ExternalRegistryForm/ImageUrlField';
import { ValidationState } from '@/pages/RestoreFromBackup/helpers';
import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

const mockOnChange = jest.fn();

const { renderComponent } = getComponentRenderer(getComponent);

describe('ImageUrlField', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should render the input field with label', () => {
    renderComponent();

    expect(screen.getByLabelText('Backup image URL')).toBeInTheDocument();
  });

  test('should render the placeholder text', () => {
    renderComponent();

    const input = screen.getByLabelText('Backup image URL');
    expect(input).toHaveAttribute('placeholder', 'registry.example.com/namespace/workspace:latest');
  });

  test('should display the provided value', () => {
    renderComponent({ value: 'registry.example.com/ns/ws:tag' });

    expect(screen.getByLabelText('Backup image URL')).toHaveValue('registry.example.com/ns/ws:tag');
  });

  test('should call onChange when user types', async () => {
    renderComponent();

    const input = screen.getByLabelText('Backup image URL');
    await userEvent.type(input, 'r');

    expect(mockOnChange).toHaveBeenCalledWith('r');
  });

  test('should display default helper text in idle state', () => {
    renderComponent({ validationState: 'idle' });

    expect(
      screen.getByText('Enter the full URL of the backup image from the source cluster.'),
    ).toBeInTheDocument();
  });

  test('should display spinner when validating', () => {
    renderComponent({ validationState: 'validating' });

    expect(screen.getByLabelText('Validating backup image')).toBeInTheDocument();
    expect(screen.getByText(/Validating backup image/)).toBeInTheDocument();
  });

  test('should display success indicator when valid', () => {
    renderComponent({
      validationState: 'valid',
      validated: ValidatedOptions.success,
    });

    expect(screen.getByText(/Backup image is valid and accessible/)).toBeInTheDocument();
  });

  test('should display workspace name when valid with metadata', () => {
    const result: BackupValidationResult = {
      valid: true,
      accessible: true,
      metadata: {
        workspaceName: 'detected-ws',
        namespace: 'ns',
        timestamp: '2026-02-11T12:00:00Z',
        sizeBytes: 512,
      },
    };

    renderComponent({
      validationState: 'valid',
      validated: ValidatedOptions.success,
      validationResult: result,
    });

    expect(screen.getByText(/detected-ws/)).toBeInTheDocument();
  });

  test('should display error text when validated is error', () => {
    renderComponent({
      validated: ValidatedOptions.error,
      error: 'Invalid image URL format.',
    });

    expect(screen.getByText('Invalid image URL format.')).toBeInTheDocument();
  });
});

type PartialProps = {
  value?: string;
  validated?: ValidatedOptions;
  error?: string;
  validationState?: ValidationState;
  validationResult?: BackupValidationResult;
};

function getComponent(overrides: PartialProps = {}) {
  return (
    <ImageUrlField
      value={overrides.value ?? ''}
      validated={overrides.validated ?? ValidatedOptions.default}
      error={overrides.error ?? ''}
      validationState={overrides.validationState ?? 'idle'}
      validationResult={overrides.validationResult ?? undefined}
      onChange={mockOnChange}
    />
  );
}
